import fs from 'fs';

const questions = [];
function q(id, question, options, correct_index, explanation) {
  questions.push({ id, question, options, correct_index, marks: 1, explanation });
}

// ===== JAVA QUESTIONS =====
// Easy (1-35)
q("java-1", "What is the correct way to declare a variable in Java that stores whole numbers?", ["int x = 5;", "integer x = 5;", "x = 5;", "int x == 5;"], 0, "int is the primitive type for 32-bit integers in Java.");
q("java-2", "Which method is the entry point of any Java application?", ["start()", "main()", "run()", "init()"], 1, "Java applications start execution from the public static void main(String[] args) method.");
q("java-3", "What does JVM stand for?", ["Java Visual Machine", "Java Virtual Machine", "Java Variable Model", "Java Verified Module"], 1, "JVM (Java Virtual Machine) executes Java bytecode and provides platform independence.");
q("java-4", "Which of these is NOT a primitive data type in Java?", ["int", "double", "String", "boolean"], 2, "String is a class (reference type) in Java, not a primitive type.");
q("java-5", "What is the output of System.out.println(10 + 5 * 2); ?", ["30", "20", "15", "70"], 1, "Multiplication has higher precedence than addition, so 5*2=10, then 10+10=20.");
q("java-6", "Which keyword is used to create a new object in Java?", ["new", "create", "object", "alloc"], 0, "The 'new' keyword allocates memory and returns a reference to the newly created object.");
q("java-7", "What is the size of an int in Java?", ["16 bits", "32 bits", "64 bits", "8 bits"], 1, "In Java, int is a 32-bit signed two's complement integer with range -2^31 to 2^31-1.");
q("java-8", "Which loop is guaranteed to execute at least once?", ["for", "while", "do-while", "enhanced for"], 2, "A do-while loop executes its body first, then checks the condition, ensuring at least one execution.");
q("java-9", "What is the default value of a boolean variable in Java?", ["true", "false", "0", "null"], 1, "In Java, boolean instance variables default to false.");
q("java-10", "Which operator is used for string concatenation in Java?", ["+", "&", ".", ","], 0, "The + operator is overloaded in Java to perform string concatenation.");
q("java-11", "What does the break statement do inside a loop?", ["Skips the current iteration", "Exits the loop immediately", "Restarts the loop", "Pauses the loop"], 1, "break terminates the innermost loop or switch statement immediately.");
q("java-12", "Which of the following is a valid Java comment style?", ["// comment", "# comment", "<!-- comment -->", "' comment"], 0, "Java supports // for single-line comments, /* */ for multi-line, and /** */ for documentation comments.");
q("java-13", "What is the range of a byte variable in Java?", ["0 to 255", "-128 to 127", "-256 to 255", "0 to 127"], 1, "byte in Java is 8 bits signed, ranging from -128 to 127 inclusive.");
q("java-14", "What is the correct syntax for a method in Java?", ["void myMethod() { }", "method void myMethod() { }", "void myMethod[] { }", "myMethod void() { }"], 0, "A method signature consists of return type, name, parameters, and body enclosed in braces.");
q("java-15", "Which data type would you use to store a true/false value?", ["boolean", "bool", "bit", "flag"], 0, "boolean is Java's primitive type for logical true/false values.");
q("java-16", "What is the output of: System.out.println(\"Java\" + 1 + 2); ?", ["Java3", "Java12", "Java 12", "3Java"], 1, "String concatenation is left-associative, so \"Java\" + 1 becomes \"Java1\", then + 2 becomes \"Java12\".");
q("java-17", "Which keyword is used to define a constant variable in Java?", ["const", "final", "static", "readonly"], 1, "The 'final' keyword prevents reassignment. 'const' is reserved but not used in Java.");
q("java-18", "What is the correct way to declare a single-dimensional array in Java?", ["int[] arr = new int[5];", "int arr[] = int[5];", "array int arr = int[5];", "int arr = new int[5];"], 0, "The preferred syntax is type[] name = new type[size];.");
q("java-19", "Which package contains the Scanner class for user input?", ["java.util", "java.io", "java.lang", "java.input"], 0, "Scanner is in java.util package and provides methods for reading various types of input.");
q("java-20", "What method is used to find the length of a String in Java?", ["length()", "size()", "getLength()", "len()"], 0, "String.length() returns the number of characters in the string. Arrays use .length (no parentheses).");
q("java-21", "Which operator checks equality of values in Java?", ["=", "==", "===", "!="], 1, "== is the equality comparison operator. = is assignment. === is not a Java operator.");
q("java-22", "What does the continue statement do?", ["Exits the loop", "Skips to the next iteration", "Restarts the loop", "Breaks out of all loops"], 1, "continue skips the remaining code in the current loop iteration and proceeds to the next iteration.");
q("java-23", "What is the default value of a reference variable in Java?", ["0", "null", "false", "undefined"], 1, "Reference variables (objects) default to null in Java.");
q("java-24", "Which of the following is a Java reserved word that is not currently used?", ["const", "goto", "both const and goto", "none"], 2, "Both const and goto are reserved keywords in Java but are not used in the language.");
q("java-25", "What is the return type of the main method?", ["void", "int", "String", "boolean"], 0, "The main method has a void return type, meaning it doesn't return a value.");
q("java-26", "Which escape sequence represents a newline in Java?", ["\\n", "\\r", "\\t", "\\b"], 0, "\\n is the newline (line feed) escape sequence in Java strings.");
q("java-27", "How do you call a method named start() on an object named car?", ["car.start()", "start(car)", "car->start()", "car::start()"], 0, "In Java, methods are called using the dot operator: object.method().");
q("java-28", "What is the result of 10 % 3 in Java?", ["3", "1", "3.33", "0"], 1, "The % (modulus) operator returns the remainder of division: 10 divided by 3 is 3 remainder 1.");
q("java-29", "Which data type has a larger range, float or double?", ["float", "double", "Same range", "Neither"], 1, "double is 64 bits while float is 32 bits, giving double a much larger range and precision.");
q("java-30", "What is the correct way to import all classes from a package?", ["import java.util.*;", "import java.util.all;", "include java.util.*;", "using java.util.*;"], 0, "The wildcard * imports all classes from the specified package (but not sub-packages).");
q("java-31", "How do you compare two strings for equality in Java?", ["str1 == str2", "str1.equals(str2)", "str1.compare(str2)", "str1 = str2"], 1, ".equals() compares the actual string content, while == compares object references.");
q("java-32", "What is the index of the first element in a Java array?", ["1", "0", "-1", "1-indexed"], 1, "Java arrays are zero-indexed, meaning the first element is at index 0.");
q("java-33", "Which keyword allows a variable to be used without creating an object of its class?", ["static", "final", "public", "abstract"], 0, "Static members belong to the class itself and can be accessed without an instance.");
q("java-34", "What is the superclass of all classes in Java?", ["Object", "Class", "Main", "Super"], 0, "java.lang.Object is the root of the Java class hierarchy; every class implicitly extends Object.");
q("java-35", "Which statement is used to make decisions based on multiple values in Java?", ["if-else", "switch", "while", "for"], 1, "switch is the branching statement that selects execution based on multiple discrete values.");
// Medium (36-70)
q("java-36", "What is method overloading in Java?", ["Multiple methods with the same name but different parameters", "Methods with different names", "Methods in different classes", "Methods that override parent methods"], 0, "Method overloading allows multiple methods with the same name but different parameter lists within the same class.");
q("java-37", "Which access modifier makes a member visible to all classes?", ["private", "default", "protected", "public"], 3, "public provides the widest visibility, accessible from any class in any package.");
q("java-38", "What is encapsulation in OOP?", ["Binding data and methods together and hiding internal state", "Inheriting from multiple classes", "Creating multiple objects from one class", "Using static methods only"], 0, "Encapsulation bundles data and methods within a class, restricting direct access to internal state.");
q("java-39", "Which keyword is used to inherit a class in Java?", ["extends", "implements", "inherits", "super"], 0, "The 'extends' keyword indicates that a class inherits from another class.");
q("java-40", "What is polymorphism in Java?", ["Ability of an object to take many forms", "Multiple classes with same name", "Many methods in one class", "Single method for all types"], 0, "Polymorphism allows objects of different types to respond to the same method call based on inheritance or interfaces.");
q("java-41", "What does the super keyword do?", ["Refers to parent class object", "Creates a new object", "Calls a static method", "Terminates the method"], 0, "super refers to the immediate parent class instance and is used to access parent members and constructors.");
q("java-42", "What is an abstract class in Java?", ["A class that cannot be instantiated and may contain abstract methods", "A class with only static methods", "A final class", "A class without any methods"], 0, "Abstract classes are declared with 'abstract' keyword, cannot be instantiated, and may contain abstract method declarations.");
q("java-43", "Which interface is used for event handling in GUI applications?", ["ActionListener", "ActionHandler", "EventController", "ClickListener"], 0, "ActionListener is an interface in java.awt.event used for handling action events like button clicks.");
q("java-44", "What is the purpose of the finally block in exception handling?", ["Always executes regardless of exception", "Only executes on exception", "Only executes on success", "Defines the exception type"], 0, "The finally block always executes after try/catch regardless of whether an exception occurred, useful for cleanup.");
q("java-45", "Which collection class stores key-value pairs?", ["HashMap", "ArrayList", "LinkedList", "HashSet"], 0, "HashMap stores key-value pairs and provides O(1) average-time complexity for get/put operations.");
q("java-46", "What is the difference between ArrayList and LinkedList?", ["ArrayList uses dynamic array, LinkedList uses doubly-linked list", "ArrayList is slower", "LinkedList can only store integers", "No difference"], 0, "ArrayList uses a resizable array for fast random access; LinkedList uses a doubly-linked list for fast insertions/deletions.");
q("java-47", "Which keyword prevents a method from being overridden?", ["final", "static", "private", "protected"], 0, "A final method cannot be overridden in subclasses. Final classes cannot be extended at all.");
q("java-48", "What is a constructor in Java?", ["A special method called when an object is instantiated", "A method that destroys objects", "A static method", "An abstract method"], 0, "Constructors are special methods with the same name as the class, called automatically when objects are created with 'new'.");
q("java-49", "What does the this keyword refer to?", ["The current object instance", "The parent class", "The current method", "A new object"], 0, "this refers to the current object instance within a class and is used to distinguish instance variables from parameters.");
q("java-50", "Which exception is thrown when a file is not found?", ["FileNotFoundException", "IOException", "ClassNotFoundException", "NullPointerException"], 0, "FileNotFoundException (a subclass of IOException) is thrown when a file with the specified path does not exist.");
q("java-51", "What is the purpose of Java generics?", ["To provide type safety and eliminate explicit casting", "To create generic objects", "To make methods run faster", "To simplify string handling"], 0, "Generics enable types (classes, interfaces) to be parameterized, providing compile-time type safety and eliminating casts.");
q("java-52", "Which type of loop is best for iterating over an array or collection?", ["Enhanced for-each loop", "While loop", "Do-while loop", "Labeled loop"], 0, "The enhanced for-each loop (for (Type var : collection)) provides clean, safe iteration over arrays and collections.");
q("java-53", "What is the output of Integer.parseInt(\"123\") ?", ["int 123", "String \"123\"", "Integer 123", "Compile error"], 0, "Integer.parseInt() converts a String representation of a number into a primitive int value.");
q("java-54", "Which package is automatically imported in all Java programs?", ["java.lang", "java.util", "java.io", "java.awt"], 0, "java.lang is automatically imported in every Java compilation unit, providing core classes like String, Math, and System.");
q("java-55", "What is the difference between checked and unchecked exceptions?", ["Checked must be caught or declared, unchecked are runtime errors", "Unchecked must be caught", "No difference", "Checked are only in Java 8+"], 0, "Checked exceptions (IOException, SQLException) must be caught or declared in throws clause; unchecked (RuntimeException) do not.");
q("java-56", "What does the StringBuilder class provide?", ["Mutable string for efficient concatenation", "Immutable strings", "String comparison", "String parsing"], 0, "StringBuilder provides a mutable sequence of characters, making string concatenation more efficient than using String.");
q("java-57", "Which lambda expression syntax is correct in Java?", ["(a, b) -> a + b", "a, b -> a + b", "(a, b) => a + b", "lambda a, b: a + b"], 0, "Java lambda syntax uses -> (arrow operator) with optional parentheses around parameters and an expression or block body.");
q("java-58", "What is the purpose of the transient keyword?", ["To mark a field that should not be serialized", "To make a field temporary", "To delete a field", "To cache a field"], 0, "Transient fields are skipped during serialization because they represent transient or derived state.");
q("java-59", "Which interface must a class implement to be used with an iterator?", ["Iterable", "Iterator", "Comparable", "Collection"], 0, "Implementing Iterable allows a class to be the target of the enhanced for-each loop and provides an iterator.");
q("java-60", "What is a lambda expression in Java?", ["An anonymous function that can be passed as argument", "A named inner class", "A static method", "A constructor"], 0, "Lambda expressions provide a concise way to represent anonymous functions, enabling functional programming in Java.");
q("java-61", "Which data structure offers O(1) average time for add, remove, and contains operations?", ["HashSet", "ArrayList", "LinkedList", "TreeSet"], 0, "HashSet, backed by a hash table, offers constant-time average performance for basic operations.");
q("java-62", "What does the volatile keyword guarantee?", ["Visibility of changes across threads", "Method execution speed", "Variable persistence", "Object immutability"], 0, "volatile ensures that changes to a variable are immediately visible to all threads by preventing thread-local caching.");
q("java-63", "What is method overriding?", ["Subclass providing specific implementation of a parent method", "Defining multiple methods with same name", "Calling a method from another class", "Overloading a method"], 0, "Method overriding occurs when a subclass provides its own implementation of a method already defined in its parent class.");
q("java-64", "Which operator is used to access a member of a class via a reference?", [".", "->", "::", "#"], 0, "The dot (.) operator is used in Java to access instance methods and fields through object references.");
q("java-65", "What is the difference between abstract class and interface?", ["Abstract classes can have constructors and instance variables, interfaces cannot (pre-Java 8)", "No difference", "Interfaces can have constructors", "Abstract classes cannot have methods"], 0, "Abstract classes can have constructors, instance variables, and concrete methods; interfaces (pre-Java 8) only declare method signatures.");
q("java-66", "How does Java handle memory management?", ["Automatic garbage collection", "Manual memory deallocation", "Reference counting", "Stack-based allocation only"], 0, "Java provides automatic garbage collection which reclaims memory from objects no longer referenced.");
q("java-67", "What is the purpose of the try-with-resources statement?", ["Automatically closes resources that implement AutoCloseable", "Catches all exceptions", "Creates new resources", "Logs resource usage"], 0, "try-with-resources ensures each resource is automatically closed at the end of the statement, simplifying cleanup code.");
q("java-68", "Which sorting algorithm does Collections.sort() use?", ["TimSort (modified merge sort)", "QuickSort", "BubbleSort", "SelectionSort"], 0, "Collections.sort() uses TimSort, a hybrid sorting algorithm derived from merge sort and insertion sort.");
q("java-69", "What is the output of Math.round(4.5)?", ["4", "5", "4.5", "5.0"], 1, "Math.round(4.5) returns 5 because it rounds to the nearest integer, with .5 rounding up.");
q("java-70", "Which keyword is used to achieve multiple inheritance of type in Java?", ["implements", "extends", "interface", "abstract"], 0, "A Java class can implement multiple interfaces, achieving multiple inheritance of type (but not implementation).");
// Hard (71-100)
q("java-71", "What is the output: Integer a = 100; Integer b = 100; System.out.println(a == b); ?", ["true", "false", "Compile error", "NullPointerException"], 0, "Java caches Integer values from -128 to 127, so == compares the same cached objects, returning true.");
q("java-72", "What is the diamond problem in Java and how is it resolved?", ["Ambiguity from multiple interface default methods; resolved by explicit override", "Circular inheritance; resolved by interfaces", "Method overloading confusion", "Nonexistent in Java"], 0, "When two interfaces provide default methods with the same signature, the implementing class must override the method to resolve ambiguity.");
q("java-73", "What is the difference between fail-fast and fail-safe iterators?", ["Fail-fast throws ConcurrentModificationException; fail-safe works on a clone", "Fail-safe is faster", "No difference", "Fail-fast is only for ArrayList"], 0, "Fail-fast iterators detect structural modification during iteration and throw ConcurrentModificationException; fail-safe iterators work on a snapshot.");
q("java-74", "How does the synchronized keyword work in Java?", ["Ensures only one thread can execute a method or block at a time", "Makes a variable read-only", "Creates a backup of data", "Pauses a thread"], 0, "synchronized acquires the intrinsic lock of an object, ensuring mutual exclusion for thread safety.");
q("java-75", "What is the purpose of the join() method in threading?", ["Waits for a thread to die", "Connects two threads", "Starts a thread", "Pauses a thread"], 0, "Thread.join() causes the current thread to wait until the specified thread completes execution.");
q("java-76", "What is a functional interface in Java?", ["An interface with exactly one abstract method", "An interface with only static methods", "A class with one method", "Any interface in java.util.function"], 0, "A functional interface has exactly one abstract method and can be implemented using a lambda expression.");
q("java-77", "What does the Stream API's map() method do?", ["Transforms each element using a function", "Filters elements by condition", "Reduces stream to a single value", "Sorts the elements"], 0, "The map() operation applies a given function to each element and returns a new stream of the results.");
q("java-78", "What is the difference between Comparator and Comparable?", ["Comparable defines natural ordering; Comparator defines custom ordering", "No difference", "Comparator is for numbers only", "Comparable is an interface; Comparator is a class"], 0, "Comparable (compareTo) defines the natural ordering of objects; Comparator (compare) defines external, custom ordering strategies.");
q("java-79", "How is thread starvation different from deadlock?", ["Starvation is when a thread is perpetually denied resources; deadlock is when threads block each other", "No difference", "Starvation only affects main thread", "Deadlock is recoverable"], 0, "Starvation occurs when a thread never gets CPU time; deadlock occurs when two or more threads each wait for locks held by the others.");
q("java-80", "What does the reflect package (java.lang.reflect) provide?", ["Ability to examine and modify runtime behavior of classes", "Memory management tools", "Database connectivity", "Network communication"], 0, "The Reflection API allows inspection and invocation of classes, methods, fields, and constructors at runtime.");
q("java-81", "What is an annotation in Java?", ["Metadata attached to code elements for compiler and runtime processing", "A code comment", "A special method", "A keyword prefix"], 0, "Annotations provide metadata about code elements that can be processed at compile time or runtime via reflection.");
q("java-82", "How does the Optional class help with null handling?", ["Wraps a value to express presence or absence explicitly", "Replaces all null checks", "Automatically handles null pointers", "Validates null parameters"], 0, "Optional provides a container object that may or may not contain a value, encouraging explicit handling of absent values.");
q("java-83", "What is the difference between ClassNotFoundException and NoClassDefFoundError?", ["CNFE occurs at compile time reflection; NCDFE occurs at runtime when class was available at compile time", "No difference", "Both are checked exceptions", "CNFE is a runtime error"], 0, "ClassNotFoundException is thrown when a class is not found via reflection; NoClassDefFoundError occurs when a class was present at compile time but missing at runtime.");
q("java-84", "What is the Java Memory Model?", ["Rules governing how threads interact through memory", "JVM heap structure", "Garbage collection algorithm", "Class loading mechanism"], 0, "The Java Memory Model defines the rules for how threads access shared variables and when changes become visible.");
q("java-85", "Which design pattern is implemented by the java.io.InputStream hierarchy?", ["Decorator", "Singleton", "Factory", "Observer"], 0, "The InputStream hierarchy uses the Decorator pattern, allowing behaviors to be added to individual objects dynamically.");
q("java-86", "What is the difference between sleep() and wait()?", ["sleep() pauses thread without releasing locks; wait() releases locks until notified", "No difference", "sleep() is static; wait() is instance", "Both release locks"], 0, "Thread.sleep() pauses execution but does not release any monitors; Object.wait() releases the monitor and waits for notification.");
q("java-87", "What is the purpose of the static initializer block?", ["Runs once when class is first loaded to initialize static fields", "Creates the main method", "Initializes instance variables", "Declares package"], 0, "The static initializer block (static { }) executes once when the class is loaded by the JVM, before any instance is created.");
q("java-88", "How are strings stored in Java?", ["In a string pool for potential reuse via interning", "On the stack", "In a database", "As character arrays only"], 0, "String literals are stored in the string pool (heap region) and can be reused; the intern() method adds Strings to the pool.");
q("java-89", "What is the difference between path and classpath?", ["Path is for OS executables; Classpath is for Java class files and libraries", "No difference", "Classpath is for source files", "Path replaces classpath"], 0, "PATH tells the OS where to find executables (like java/javac). CLASSPATH tells the JVM where to find class files and JARs.");
q("java-90", "What does the assert keyword do in Java?", ["Enables runtime assertions for debugging", "Declares a constant", "Throws an exception", "Creates an assertion object"], 0, "assert evaluates a boolean expression and throws AssertionError if false, used for debugging and testing invariants.");
q("java-91", "How does the Comparable interface differ from Comparator in sorting?", ["Comparable modifies the class itself; Comparator is external sorting logic", "No difference", "Comparator is for primitive types", "Comparable is deprecated"], 0, "Implementing Comparable changes the class's natural ordering. Comparator allows creating multiple different sorting strategies externally.");
q("java-92", "What is a marker interface in Java?", ["An interface with no methods (e.g., Serializable, Cloneable)", "An interface marking the main method", "An interface with one method", "A deprecated interface"], 0, "Marker interfaces declare no methods but signal to the JVM or runtime that a class has specific capabilities (e.g., Serializable).");
q("java-93", "What is stack unwinding in exception handling?", ["Process of searching catch blocks up the call stack", "Removing variables from stack", "Stack memory allocation", "Thread synchronization"], 0, "When an exception is not caught in the current method, the call stack is searched for an appropriate handler in the calling methods.");
q("java-94", "What is the difference between StringBuilder and StringBuffer?", ["StringBuilder is not synchronized (faster); StringBuffer is synchronized (thread-safe)", "No difference", "StringBuffer is newer", "StringBuilder is for single characters"], 0, "StringBuffer's methods are synchronized for thread safety; StringBuilder provides identical API but without synchronization for better performance.");
q("java-95", "How does garbage collection identify unreachable objects?", ["Through root set analysis starting from GC roots", "By reference counting", "By tracking all object allocations", "Using static analysis"], 0, "The garbage collector identifies live objects by tracing from GC roots (stack variables, static fields, etc.); unreachable objects are eligible for collection.");
q("java-96", "What is the try-with-resources enhancement in Java 9?", ["Resources can be declared outside try before use", "Multiple resources are supported", "No change", "Resources are automatically created"], 0, "Java 9 improved try-with-resources to allow referencing effectively-final variables declared outside the try block.");
q("java-97", "What does the module system (JPMS) introduced in Java 9 provide?", ["Strong encapsulation and reliable configuration for large applications", "Faster compilation", "New data types", "Replaces packages"], 0, "The Java Platform Module System (Project Jigsaw) allows grouping packages into modules with explicit dependencies and exports.");
q("java-98", "How does the ForkJoinPool differ from ThreadPoolExecutor?", ["ForkJoinPool implements work-stealing; ThreadPoolExecutor uses a work queue", "No difference", "ForkJoinPool is for I/O tasks", "ThreadPoolExecutor uses fork-join"], 0, "ForkJoinPool uses work-stealing where idle threads steal tasks from busy threads' queues, optimizing CPU-bound parallel processing.");
q("java-99", "What is a sealed class in Java 17?", ["A class that restricts which other classes may extend it", "A final class", "An abstract class", "A private class"], 0, "Sealed classes (sealed keyword) allow a class or interface to control which classes may implement or extend it.");
q("java-100", "What is a record in modern Java?", ["A concise class declaration for immutable data carriers", "A database record", "A log entry", "A serialized object"], 0, "Records (Java 14+) provide a compact syntax for declaring immutable data classes with automatically generated constructor, accessors, equals, hashCode, and toString.");

