q("javascript-7", "What is the result of '5' + 3 in JavaScript?", ["53", "8", "error", "'5+3'"], 0, "When a string is involved with +, JavaScript performs string concatenation, converting 3 to '3'.");
q("javascript-8", "Which event occurs when a user clicks on an HTML element?", ["onclick", "onhover", "onpress", "ontap"], 0, "The onclick event is triggered when the user clicks on an element.");
q("javascript-9", "What is the correct way to access the value of an input field with id=\"name\"?", ["document.getElementById('name').value", "document.name.value", "input.name.value", "getElementById('name')"], 0, "document.getElementById() returns the element, and .value accesses its current input value.");
q("javascript-10", "What does the console.log() function do?", ["Outputs data to the browser console", "Displays an alert box", "Writes to the HTML document", "Sends data to the server"], 0, "console.log() prints messages to the browser's developer console for debugging purposes.");
