q("javascript-12", "What is the data type of the value false?", ["boolean", "Boolean", "bool", "logical"], 0, "false is a boolean primitive type in JavaScript.");
q("javascript-13", "How do you find the length of a string in JavaScript?", [".length", ".size()", ".len()", ".count()"], 0, ".length is a property (not a method) that returns the number of characters in a string.");
q("javascript-14", "What keyword is used to define a constant in JavaScript?", ["const", "let", "var", "final"], 0, "const declares a constant that cannot be reassigned once defined (ES6+).");
q("javascript-15", "Which method removes the last element from an array?", ["pop()", "push()", "shift()", "unshift()"], 0, "pop() removes and returns the last element of an array, modifying the original array.");
q("javascript-16", "What is the output of Boolean(\"false\") ?", ["true", "false", "Error", "undefined"], 0, "Any non-empty string (including \"false\") converts to true when coerced to boolean.");
q("javascript-17", "Which operator is used to assign a value to a variable?", ["=", "==", "===", "=>"], 0, "= is the assignment operator; == and === are comparison operators.");
q("javascript-18", "How do you create a function in JavaScript?", ["function myFunc() {}", "func myFunc() {}", "create function myFunc() {}", "def myFunc() {}"], 0, "The function keyword followed by name, parameters, and body defines a function in JavaScript.");
q("javascript-19", "What is the result of 10 % 3 in JavaScript?", ["1", "3", "3.33", "0"], 0, "The modulus operator % returns the remainder of division: 10 / 3 = 3 remainder 1.");
