q("php-40", "How does filter_var() validate an email?", ["filter_var($email, FILTER_VALIDATE_EMAIL)", "validate_email($email)", "check_email($email)", "preg_match_email($email)"], 0, "filter_var() with FILTER_VALIDATE_EMAIL validates email format according to RFC standards.");
